// Test stackalloc Span<nint> and Span<nuint>
Span<nint> signed = stackalloc nint[] { 1, 2, 3, 4, 5 };
Span<nuint> unsigned = stackalloc nuint[] { 10, 20, 30 };

Console.WriteLine($"nint size: {sizeof(nint)} bytes");
Console.WriteLine($"Span<nint> length: {signed.Length}");
for (int i = 0; i < signed.Length; i++)
    Console.WriteLine($"  signed[{i}] = {signed[i]}");

Console.WriteLine($"Span<nuint> length: {unsigned.Length}");
for (int i = 0; i < unsigned.Length; i++)
    Console.WriteLine($"  unsigned[{i}] = {unsigned[i]}");

// Also test stackalloc with a count (not initializer)
Span<nint> zeroed = stackalloc nint[8];
Console.WriteLine($"Zeroed Span<nint> length: {zeroed.Length}, first={zeroed[0]}, last={zeroed[7]}");

Console.WriteLine("All stackalloc Span<nint/nuint> tests passed!");

